		writeInt(-1);
	} else if (arr.length == 0) {
		writeInt(0);
		writeByteArray(null);
	} else {
		BitSet bits = new BitSet(arr.length);
		for (int i = 0; i < arr.length; i++) {
			bits.set(i, arr[i]);
		}
		writeInt(arr.length);
		writeByteArray(bits.toByteArray());
	}
}

