			            + servletPath + "' instead.");
		}
		// for anything but /initialsetup
		else if (!httpRequest.getServletPath().equals("/" + WebConstants.SETUP_PAGE_URL)
		        && !httpRequest.getServletPath().equals("/" + AUTO_RUN_OPENMRS)) {
			// send the user to the setup page
