			}
			//  Finish up
			//project.setSessionProperty(buildInfoProperty, buildInfo);
			setLoaddedBuildInfo(project, buildInfo);
		}
	}

	if (buildInfo != null) {
		buildInfo.setValid(true);
	}
	return buildInfo;
}

