    } catch (TransformerException te) {
      throw new PSQLException(GT.tr("Unable to convert DOMResult SQLXML data to a string."),
          PSQLState.DATA_ERROR, te);
    } finally {
      domResult = null;
      active = false;
    }
  }
}

